-- Fix 1: Missing id_mappings table
-- Error: relation "id_mappings" does not exist
-- Migration: 20260219000100_identity.sql
-- PULLBACK NOTE: Restored id_mappings table that was accidentally removed
-- OLD: Table was missing from identity module
-- NEW: Added complete id_mappings table with proper constraints

CREATE TABLE IF NOT EXISTS public.id_mappings (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    entity_id UUID NOT NULL,
    display_id TEXT NOT NULL UNIQUE,
    entity_type TEXT NOT NULL CHECK (entity_type IN ('patient', 'provider', 'hospital', 'admin', 'dispatcher', 'doctor', 'ambulance', 'driver', 'emergency_request', 'visit', 'organization', 'payment', 'notification', 'wallet')),
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_id_mappings_entity_id ON public.id_mappings(entity_id);
CREATE INDEX IF NOT EXISTS idx_id_mappings_display_id ON public.id_mappings(display_id);
CREATE INDEX IF NOT EXISTS idx_id_mappings_entity_type ON public.id_mappings(entity_type);

-- Fix 2: Missing display_id columns in financial tables
