-- PULLBACK NOTE: Added missing display_id columns to financial tables
-- OLD: Financial tables missing display_id columns
-- NEW: Added display_id columns to all financial tables

ALTER TABLE public.patient_wallets ADD COLUMN IF NOT EXISTS display_id TEXT UNIQUE;
ALTER TABLE public.organization_wallets ADD COLUMN IF NOT EXISTS display_id TEXT UNIQUE;
ALTER TABLE public.payments ADD COLUMN IF NOT EXISTS display_id TEXT UNIQUE;

-- Fix 3: Missing display_id column in notifications table
