-- Fix 5: Missing display_id triggers
-- Error: display_id not being generated for new records
-- Migration: 20260219000100_identity.sql
-- PULLBACK NOTE: Added missing display_id generation triggers
-- OLD: New records missing display_id values
-- NEW: Triggers ensure display_id generation for all entities

CREATE OR REPLACE FUNCTION public.stamp_entity_display_id()
RETURNS TRIGGER AS $$
DECLARE
    v_prefix TEXT;
    v_display_id TEXT;
BEGIN
    -- Determine prefix based on table name
    v_prefix := CASE TG_TABLE_NAME
        WHEN 'profiles' THEN 'PAT'
        WHEN 'organizations' THEN 'ORG'
        WHEN 'hospitals' THEN 'HOS'
        WHEN 'doctors' THEN 'DOC'
        WHEN 'ambulances' THEN 'AMB'
        WHEN 'emergency_requests' THEN 'EMR'
        WHEN 'visits' THEN 'VIS'
        WHEN 'payments' THEN 'PAY'
        WHEN 'notifications' THEN 'NOT'
        WHEN 'patient_wallets' THEN 'PWA'
        WHEN 'organization_wallets' THEN 'OWA'
        ELSE 'ENT'
    END;
    
    -- Generate unique display ID
    v_display_id := v_prefix || '-' || LPAD(EXTRACT(MICROSECONDS FROM NOW())::TEXT, 6, '0');
    
    -- Insert into id_mappings table
    INSERT INTO public.id_mappings (
        entity_id,
        display_id,
        entity_type
    ) VALUES (
        NEW.id,
        v_display_id,
        TG_TABLE_NAME
    );
    
    -- Set display_id on the record
    NEW.display_id := v_display_id;
    
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Create triggers for all tables with display_id
DROP TRIGGER IF EXISTS on_profiles_display_id ON public.profiles;
CREATE TRIGGER on_profiles_display_id
BEFORE INSERT ON public.profiles
FOR EACH ROW EXECUTE PROCEDURE public.stamp_entity_display_id();

DROP TRIGGER IF EXISTS on_organizations_display_id ON public.organizations;
CREATE TRIGGER on_organizations_display_id
