-- ============================================================================
-- VALIDATION QUERIES
-- ============================================================================

-- Validation Query 1: Check all required tables exist
SELECT 
    table_name,
    table_type
FROM information_schema.tables 
WHERE table_schema = 'public' 
    AND table_name IN (
        'profiles', 'organizations', 'hospitals', 'doctors', 'ambulances',
        'emergency_requests', 'visits', 'patient_wallets', 'organization_wallets',
        'payments', 'notifications', 'id_mappings'
    )
ORDER BY table_name;

-- Validation Query 2: Check display_id columns exist
SELECT 
    table_name,
    column_name,
    data_type
FROM information_schema.columns 
WHERE table_schema = 'public' 
    AND column_name = 'display_id'
ORDER BY table_name;

-- Validation Query 3: Check triggers exist
SELECT 
    trigger_name,
    event_manipulation,
    event_object_table,
    action_timing
FROM information_schema.triggers 
WHERE trigger_schema = 'public' 
    AND trigger_name LIKE '%display_id%'
ORDER BY trigger_name;

-- Validation Query 4: Check indexes exist
SELECT 
    indexname,
    tablename,
    indexdef
FROM pg_indexes 
WHERE schemaname = 'public' 
    AND (indexname LIKE '%display_id%' OR indexname LIKE '%location%')
ORDER BY tablename, indexname;

